/**
 * User notification preferences model.
 *
 * Supports per-channel settings for email, SMS, and webhook.
 * Legacy email-only fields (emailEnabled, emailFrequency) are preserved
 * for backward compatibility and kept in sync with channelPreferences.email.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * How frequently email notifications are delivered.
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Base preference for a notification channel.
 */
export interface ChannelPreference {
  enabled: boolean;
}

/**
 * Email-specific preference with frequency control.
 */
export interface EmailChannelPreference extends ChannelPreference {
  frequency: EmailFrequency;
}

/**
 * Per-channel preference map.
 */
export interface ChannelPreferences {
  email: EmailChannelPreference;
  sms: ChannelPreference;
  webhook: ChannelPreference;
}

/**
 * User notification preferences.
 *
 * The `emailEnabled` and `emailFrequency` fields are kept for backward
 * compatibility. They mirror `channelPreferences.email.enabled` and
 * `channelPreferences.email.frequency` respectively.
 */
export interface UserPreferences {
  userId: string;
  /** @deprecated Use channelPreferences.email.enabled */
  emailEnabled: boolean;
  /** @deprecated Use channelPreferences.email.frequency */
  emailFrequency: EmailFrequency;
  subscribedCategories: NotificationType[];
  channelPreferences: ChannelPreferences;
  updatedAt: Date;
}

/**
 * Input for updating user preferences. All fields optional — only
 * specified fields are changed.
 *
 * Legacy email fields still work and are synced with channelPreferences.email.
 * If both legacy fields and channelPreferences.email are provided,
 * channelPreferences.email takes precedence.
 */
export interface UpdatePreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
  channelPreferences?: Partial<{
    email: Partial<EmailChannelPreference>;
    sms: Partial<ChannelPreference>;
    webhook: Partial<ChannelPreference>;
  }>;
}

/**
 * All notification types — used as the default subscription set.
 */
export const ALL_NOTIFICATION_TYPES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default channel preferences.
 * Email is opt-out (enabled by default), SMS and webhook are opt-in.
 */
export function createDefaultChannelPreferences(): ChannelPreferences {
  return {
    email: { enabled: true, frequency: 'immediate' },
    sms: { enabled: false },
    webhook: { enabled: false },
  };
}

/**
 * Create default preferences for a user.
 * Email enabled with immediate delivery; SMS and webhook disabled (opt-in).
 */
export function createDefaultPreferences(userId: string): UserPreferences {
  const channelPreferences = createDefaultChannelPreferences();
  return {
    userId,
    emailEnabled: channelPreferences.email.enabled,
    emailFrequency: channelPreferences.email.frequency,
    subscribedCategories: [...ALL_NOTIFICATION_TYPES],
    channelPreferences,
    updatedAt: new Date(),
  };
}

/**
 * Check if a channel is enabled in channel preferences.
 */
export function isChannelEnabled(
  prefs: UserPreferences,
  channel: NotificationChannel,
): boolean {
  switch (channel) {
    case 'email':
      return prefs.channelPreferences.email.enabled;
    case 'sms':
      return prefs.channelPreferences.sms.enabled;
    case 'webhook':
      return prefs.channelPreferences.webhook.enabled;
    default:
      return false;
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Stores preferences in-memory keyed by userId. Users who have not
 * explicitly set preferences get defaults (all enabled, immediate frequency).
 *
 * Supports per-channel preferences: email, SMS, and webhook.
 * Legacy email-only fields are kept in sync with channelPreferences.email.
 */

import type { NotificationType, NotificationChannel } from '../models/notification.js';
import type {
  UserPreferences,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import { createDefaultPreferences, isChannelEnabled } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserPreferences> = new Map();

  /**
   * Get preferences for a user. Returns defaults if none have been set.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.preferences.get(userId);
    if (existing) {
      return {
        ...existing,
        subscribedCategories: [...existing.subscribedCategories],
        channelPreferences: {
          email: { ...existing.channelPreferences.email },
          sms: { ...existing.channelPreferences.sms },
          webhook: { ...existing.channelPreferences.webhook },
        },
      };
    }
    return createDefaultPreferences(userId);
  }

  /**
   * Update preferences for a user. Creates preferences if they don't exist.
   * Only the fields present in the input are changed.
   *
   * Legacy email fields (emailEnabled, emailFrequency) are synced with
   * channelPreferences.email. If both are provided, channelPreferences takes precedence.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
    const current = this.getPreferences(userId);

    const updated: UserPreferences = {
      ...current,
      updatedAt: new Date(),
    };

    // Apply subscribedCategories if provided
    if (input.subscribedCategories !== undefined) {
      updated.subscribedCategories = [...input.subscribedCategories];
    }

    // Apply legacy email fields first
    if (input.emailEnabled !== undefined) {
      updated.emailEnabled = input.emailEnabled;
      updated.channelPreferences.email.enabled = input.emailEnabled;
    }
    if (input.emailFrequency !== undefined) {
      updated.emailFrequency = input.emailFrequency;
      updated.channelPreferences.email.frequency = input.emailFrequency;
    }

    // Apply channelPreferences (takes precedence over legacy fields)
    if (input.channelPreferences) {
      if (input.channelPreferences.email) {
        if (input.channelPreferences.email.enabled !== undefined) {
          updated.channelPreferences.email.enabled = input.channelPreferences.email.enabled;
          updated.emailEnabled = input.channelPreferences.email.enabled;
        }
        if (input.channelPreferences.email.frequency !== undefined) {
          updated.channelPreferences.email.frequency = input.channelPreferences.email.frequency;
          updated.emailFrequency = input.channelPreferences.email.frequency;
        }
      }
      if (input.channelPreferences.sms) {
        if (input.channelPreferences.sms.enabled !== undefined) {
          updated.channelPreferences.sms.enabled = input.channelPreferences.sms.enabled;
        }
      }
      if (input.channelPreferences.webhook) {
        if (input.channelPreferences.webhook.enabled !== undefined) {
          updated.channelPreferences.webhook.enabled = input.channelPreferences.webhook.enabled;
        }
      }
    }

    this.preferences.set(userId, updated);
    this.logger.info(`Updated preferences for user ${userId}`);
    return this.getPreferences(userId);
  }

  /**
   * Check whether a notification should be sent to a user based on their preferences.
   * Returns true if the notification should be delivered immediately.
   *
   * @param channel - The notification channel to check. Defaults to 'email' for backward compatibility.
   */
  shouldSendNotification(
    userId: string,
    notificationType: NotificationType,
    channel: NotificationChannel = 'email',
  ): boolean {
    const prefs = this.getPreferences(userId);

    // Check if the channel is enabled
    if (!isChannelEnabled(prefs, channel)) {
      return false;
    }

    // Check category subscription
    if (!prefs.subscribedCategories.includes(notificationType)) {
      return false;
    }

    // Email has frequency-based suppression (only send 'immediate')
    if (channel === 'email' && prefs.channelPreferences.email.frequency !== 'immediate') {
      return false;
    }

    return true;
  }

  /**
   * Reset a user's preferences to defaults.
   */
  resetPreferences(userId: string): UserPreferences {
    const defaults = createDefaultPreferences(userId);
    this.preferences.set(userId, defaults);
    this.logger.info(`Reset preferences for user ${userId}`);
    return this.getPreferences(userId);
  }

  /**
   * Delete stored preferences for a user. Future calls to getPreferences
   * will return defaults.
   */
  deletePreferences(userId: string): boolean {
    const deleted = this.preferences.delete(userId);
    if (deleted) {
      this.logger.info(`Deleted preferences for user ${userId}`);
    }
    return deleted;
  }

  /**
   * Clear all stored preferences (useful for testing).
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

